const pageSectionSidebarDefaultWidth = 175;
const pageSectionSidebarMinWidth = 120;
const pageSectionSidebarMaxWidth = 220;
const pageSectionSidebarSnapThreshold = 10;
const railDefaultExpandedWidth = 175;
const railMinExpandedWidth = 120;
const railMaxExpandedWidth = 260;
const railSnapThreshold = 10;
const appShortcutsStorageKey = "telnyx-link-app-shortcuts";
const defaultDesktopShortcuts: DesktopShortcutBinding[] = [
  { id: "shortcut-open-chat", actionId: "open-chat", shortcut: "Meta+1" },
  { id: "shortcut-open-settings", actionId: "open-settings", shortcut: "Meta+Comma" },
  { id: "shortcut-open-start", actionId: "open-start", shortcut: "Meta+Shift+1" },
];
const localPhoneContactsStorageKey = "telnyx-link-local-phone-contacts";

function emptyLocalPhoneContactDraft(): LocalPhoneContactDraft {
  return {
    name: "",
    role: "",
    phone: "",
    detail: "",
  };
}

function isDesktopShortcutActionId(value: string): value is DesktopShortcutActionId {
  return [
    "open-start",
    "open-chat",
    "open-settings",
    "open-calendar",
    "open-phone",
    "open-docs",
    "open-agents",
    "open-skills",
    "open-tools",
    "new-chat",
  ].includes(value);
}

function readDesktopShortcutBindings(): DesktopShortcutBinding[] {
  if (typeof window === "undefined") return defaultDesktopShortcuts;
  try {
    const stored = JSON.parse(window.localStorage.getItem(appShortcutsStorageKey) ?? "null");
    if (!Array.isArray(stored)) return defaultDesktopShortcuts;
    const parsed = stored.filter((binding): binding is DesktopShortcutBinding => Boolean(
      binding
      && typeof binding.id === "string"
      && typeof binding.shortcut === "string"
      && typeof binding.actionId === "string"
      && isDesktopShortcutActionId(binding.actionId),
    ));
    return parsed.length > 0 ? parsed : defaultDesktopShortcuts;
  } catch {
    return defaultDesktopShortcuts;
  }
}

function shortcutEventToString(event: KeyboardEvent) {
  const key = event.key;
  if (["Meta", "Shift", "Alt", "Control"].includes(key)) return "";
  const normalizedKey = key === "," ? "Comma" : key === "." ? "Period" : key.length === 1 ? key.toUpperCase() : key;
  const modifiers = [
    event.metaKey ? "Meta" : "",
    event.ctrlKey ? "Control" : "",
    event.altKey ? "Alt" : "",
    event.shiftKey ? "Shift" : "",
  ].filter(Boolean);
  if (modifiers.length === 0) return "";
  return [...modifiers, normalizedKey].join("+");
}

function PageSectionSidebar<T extends string>({
  tabs,
  groups,
  heading,
  headingIcon: HeadingIcon,
  activeTab,
  onSelect,
  label,
  resizable = true,
}: {
  tabs?: readonly PageSectionTab<T>[];
  groups?: readonly PageSectionTabGroup<T>[];
  heading?: string;
  headingIcon?: AppIcon;
  activeTab: T;
  onSelect: (tab: T) => void;
  label: string;
  resizable?: boolean;
}) {
  const sidebarRef = useRef<HTMLElement | null>(null);
  const sidebarDragRef = useRef<{
    startX: number;
    startWidth: number;
    shell: HTMLElement | null;
    lastWidth: number;
  } | null>(null);

  function setSidebarWidth(width: number) {
    const clampedWidth = Math.min(pageSectionSidebarMaxWidth, Math.max(pageSectionSidebarMinWidth, Math.round(width)));
    const snappedWidth = Math.abs(clampedWidth - pageSectionSidebarDefaultWidth) <= pageSectionSidebarSnapThreshold
      ? pageSectionSidebarDefaultWidth
      : clampedWidth;
    const shell = sidebarRef.current?.closest<HTMLElement>(".pageSectionShell");
    shell?.style.setProperty("--page-section-sidebar-width", `${snappedWidth}px`);
    return snappedWidth;
  }

  function resetSidebarWidth() {
    const shell = sidebarRef.current?.closest<HTMLElement>(".pageSectionShell");
    shell?.style.removeProperty("--page-section-sidebar-width");
  }

  function startSidebarResize(event: ReactPointerEvent<HTMLDivElement>) {
    const shell = sidebarRef.current?.closest<HTMLElement>(".pageSectionShell") ?? null;
    const startWidth = sidebarRef.current?.getBoundingClientRect().width ?? pageSectionSidebarDefaultWidth;
    sidebarDragRef.current = {
      startX: event.clientX,
      startWidth,
      shell,
      lastWidth: startWidth,
    };
    event.currentTarget.setPointerCapture(event.pointerId);
    event.preventDefault();
  }

  function resizeSidebar(event: ReactPointerEvent<HTMLDivElement>) {
    const drag = sidebarDragRef.current;
    if (!drag) return;
    const width = drag.startWidth + event.clientX - drag.startX;
    const clampedWidth = Math.min(pageSectionSidebarMaxWidth, Math.max(pageSectionSidebarMinWidth, Math.round(width)));
    drag.lastWidth = clampedWidth;
    drag.shell?.style.setProperty("--page-section-sidebar-width", `${clampedWidth}px`);
  }

  function stopSidebarResize() {
    const drag = sidebarDragRef.current;
    if (!drag) return;
    if (Math.abs(drag.lastWidth - pageSectionSidebarDefaultWidth) <= pageSectionSidebarSnapThreshold) {
      drag.shell?.style.removeProperty("--page-section-sidebar-width");
    }
    sidebarDragRef.current = null;
  }

  function adjustSidebarWidth(delta: number) {
    const currentWidth = sidebarRef.current?.getBoundingClientRect().width ?? pageSectionSidebarDefaultWidth;
    setSidebarWidth(currentWidth + delta);
  }

  const renderTabButton = ([id, tabLabel, Icon]: PageSectionTab<T>) => (
    <button
      key={id}
      className={activeTab === id ? "selected" : ""}
      onClick={() => onSelect(id)}
      role="tab"
      aria-selected={activeTab === id}
    >
      <span className="pageSectionSidebarIcon"><Icon size={17} /></span>
      <span>{tabLabel}</span>
    </button>
  );

  return (
    <aside className="pageSectionSidebar" ref={sidebarRef}>
      <div className="pageSectionSidebarTabs" role="tablist" aria-label={label}>
        {heading && (
          <div className="pageSectionSidebarHeading">
            <span className="pageSectionSidebarHeadingInner">
              {HeadingIcon && <span className="pageSectionSidebarIcon"><HeadingIcon size={15} /></span>}
              <span>{heading}</span>
            </span>
          </div>
        )}
        {groups
          ? groups.map((group) => (
            <div className="pageSectionSidebarGroup" key={group.title}>
              <div className="pageSectionSidebarGroupTitle">{group.title}</div>
              {group.tabs.map(renderTabButton)}
            </div>
          ))
          : tabs?.map(renderTabButton)}
      </div>
      {resizable && (
        <div
          className="pageSectionSidebarResizeHandle"
          role="separator"
          aria-orientation="vertical"
          aria-label="Resize submenu"
          title="Drag to resize. Double-click to reset."
          tabIndex={0}
          onDoubleClick={resetSidebarWidth}
          onPointerDown={startSidebarResize}
          onPointerMove={resizeSidebar}
          onPointerUp={stopSidebarResize}
          onPointerCancel={stopSidebarResize}
          onKeyDown={(event) => {
            if (event.key === "ArrowLeft") {
              event.preventDefault();
              adjustSidebarWidth(-10);
            } else if (event.key === "ArrowRight") {
              event.preventDefault();
              adjustSidebarWidth(10);
            } else if (event.key === "Home" || event.key === "Enter") {
              event.preventDefault();
              resetSidebarWidth();
            }
          }}
        />
      )}
    </aside>
  );
}

function GetStartedFlowPanels({
  configurationSteps,
  learningSteps,
}: {
  configurationSteps: Array<{
    id: string;
    title: string;
    description: string;
    bullets: string[];
    ctaLabel: string;
    onCtaClick: () => void;
    icon: AppIcon;
    complete: boolean;
    onToggleComplete: (checked: boolean) => void;
  }>;
  learningSteps: Array<{
    id: string;
    title: string;
    description: string;
    bullets: string[];
    ctaLabel: string;
    onCtaClick: () => void;
    icon: AppIcon;
    complete: boolean;
    onToggleComplete: (checked: boolean) => void;
  }>;
}) {
  const [singleCardPages, setSingleCardPages] = useState(false);
  const configurationPages = useMemo(() => {
    const pages = [] as typeof configurationSteps[];
    const stepsPerPage = singleCardPages ? 1 : 2;
    for (let index = 0; index < configurationSteps.length; index += stepsPerPage) {
      pages.push(configurationSteps.slice(index, index + stepsPerPage));
    }
    return pages.length > 0 ? pages : [[]];
  }, [configurationSteps, singleCardPages]);
  const learningPages = useMemo(() => {
    const pages = [] as typeof learningSteps[];
    const stepsPerPage = singleCardPages ? 1 : 2;
    for (let index = 0; index < learningSteps.length; index += stepsPerPage) {
      pages.push(learningSteps.slice(index, index + stepsPerPage));
    }
    return pages.length > 0 ? pages : [[]];
  }, [learningSteps, singleCardPages]);
  const configurationPageCount = Math.max(1, configurationPages.length);
  const learningPageCount = Math.max(1, learningPages.length);
  const [configurationPage, setConfigurationPage] = useState(0);
  const [learningPage, setLearningPage] = useState(0);
  const configurationScrollerRef = useRef<HTMLDivElement | null>(null);
  const learningScrollerRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    function syncPagerLayout() {
      setSingleCardPages(window.innerWidth <= 1380);
    }

    syncPagerLayout();
    window.addEventListener("resize", syncPagerLayout);
    return () => window.removeEventListener("resize", syncPagerLayout);
  }, []);

  useEffect(() => {
    setConfigurationPage((current) => Math.min(current, configurationPageCount - 1));
  }, [configurationPageCount]);

  useEffect(() => {
    setLearningPage((current) => Math.min(current, learningPageCount - 1));
  }, [learningPageCount]);

  useEffect(() => {
    if (!configurationScrollerRef.current) return;
    configurationScrollerRef.current.scrollTo({ left: configurationScrollerRef.current.clientWidth * configurationPage, behavior: "auto" });
  }, [configurationPage, configurationPageCount, singleCardPages]);

  useEffect(() => {
    if (!learningScrollerRef.current) return;
    learningScrollerRef.current.scrollTo({ left: learningScrollerRef.current.clientWidth * learningPage, behavior: "auto" });
  }, [learningPage, learningPageCount, singleCardPages]);

  function scrollToPage(scroller: HTMLDivElement | null, nextPage: number) {
    if (!scroller) return;
    scroller.scrollTo({ left: scroller.clientWidth * nextPage, behavior: "smooth" });
  }

  function renderStepHeader(
    title: string,
    page: number,
    pageCount: number,
    setPage: (nextPage: number) => void,
    scrollerRef: { current: HTMLDivElement | null },
  ) {
    return (
      <div className="onboardingFlowPanelHeader">
        <strong>{title}</strong>
        <div className="onboardingFlowPanelHeaderControls">
          <div className="onboardingFlowProgressBars" role="tablist" aria-label={`${title} progress`}>
            {Array.from({ length: pageCount }, (_, index) => (
              <button
                key={`${title}-${index}`}
                type="button"
                role="tab"
                aria-selected={page === index}
                className={`onboardingFlowProgressBar ${page === index ? "selected" : ""}`}
                onClick={() => {
                  setPage(index);
                  scrollToPage(scrollerRef.current, index);
                }}
                aria-label={`${title} page ${index + 1} of ${pageCount}`}
                title={`${title} page ${index + 1}`}
              />
            ))}
          </div>
          <div className="onboardingFlowProgressNav">
            <button
              type="button"
              className="onboardingFlowProgressArrow"
              onClick={() => {
                const nextPage = Math.max(0, page - 1);
                setPage(nextPage);
                scrollToPage(scrollerRef.current, nextPage);
              }}
              aria-label={`Previous ${title.toLowerCase()} step`}
              title={`Previous ${title.toLowerCase()} step`}
              disabled={page === 0}
            >
              <ArrowLeft size={14} />
            </button>
            <button
              type="button"
              className="onboardingFlowProgressArrow"
              onClick={() => {
                const nextPage = Math.min(pageCount - 1, page + 1);
                setPage(nextPage);
                scrollToPage(scrollerRef.current, nextPage);
              }}
              aria-label={`Next ${title.toLowerCase()} step`}
              title={`Next ${title.toLowerCase()} step`}
              disabled={page === pageCount - 1}
            >
              <ArrowRight size={14} />
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="onboardingFlowGrid">
      <section className="onboardingFlowPanel" aria-label="Configure Cloud Link steps">
        <div className="onboardingFlowPanelBody">
          <div
            className="onboardingHeroScroller"
            ref={configurationScrollerRef}
          >
            {[(configurationPages[configurationPage] ?? [])].map((steps) => (
              <div className="onboardingHeroStepPage" key={`configuration-page-${configurationPage}`}>
                <div className="onboardingHeroStepList">
                  {steps.map((step) => {
                    const Icon = step.icon;
                    return (
                      <article className="onboardingHeroStepCard" key={step.id}>
                        <div className="onboardingHeroStepCardHeader">
                          <span className="onboardingHeroStepIcon" aria-hidden="true">
                            <Icon size={22} />
                          </span>
                          <h3 title={step.title}>{step.title}</h3>
                        </div>
                        <p>{step.description}</p>
                        <ul className="onboardingHeroStepBullets">
                          {step.bullets.map((bullet) => (
                            <li key={bullet}>{bullet}</li>
                          ))}
                        </ul>
                        <div className="onboardingHeroStepActions">
                          <button className="button primary" type="button" onClick={step.onCtaClick}>
                            {step.ctaLabel}
                          </button>
                          <label className={`onboardingHeroStepComplete ${step.complete ? "checked" : ""}`}>
                            <input
                              type="checkbox"
                              checked={step.complete}
                              onChange={(event) => step.onToggleComplete(event.target.checked)}
                            />
                            <span>{step.complete ? "Done" : "Complete"}</span>
                          </label>
                        </div>
                      </article>
                    );
                  })}
                </div>
              </div>
            ))}
          </div>
        </div>
        {renderStepHeader("Setup", configurationPage, configurationPageCount, setConfigurationPage, configurationScrollerRef)}
      </section>
      <section className="onboardingFlowPanel" aria-label="Learn Cloud Link steps">
        <div className="onboardingFlowPanelBody">
          <div
            className="onboardingHeroScroller"
            ref={learningScrollerRef}
          >
            {[(learningPages[learningPage] ?? [])].map((steps) => (
              <div className="onboardingHeroStepPage" key={`learning-page-${learningPage}`}>
                <div className="onboardingHeroStepList">
                  {steps.map((step) => {
                    const Icon = step.icon;
                    return (
                      <article className="onboardingHeroStepCard" key={step.id}>
                        <div className="onboardingHeroStepCardHeader">
                          <span className="onboardingHeroStepIcon" aria-hidden="true">
                            <Icon size={22} />
                          </span>
                          <h3 title={step.title}>{step.title}</h3>
                        </div>
                        <p>{step.description}</p>
                        <ul className="onboardingHeroStepBullets">
                          {step.bullets.map((bullet) => (
                            <li key={bullet}>{bullet}</li>
                          ))}
                        </ul>
                        <div className="onboardingHeroStepActions">
                          <button className="button primary" type="button" onClick={step.onCtaClick}>
                            {step.ctaLabel}
                          </button>
                          <label className={`onboardingHeroStepComplete ${step.complete ? "checked" : ""}`}>
                            <input
                              type="checkbox"
                              checked={step.complete}
                              onChange={(event) => step.onToggleComplete(event.target.checked)}
                            />
                            <span>{step.complete ? "Done" : "Complete"}</span>
                          </label>
                        </div>
                      </article>
                    );
                  })}
                </div>
              </div>
            ))}
          </div>
        </div>
        {renderStepHeader("Learn Cloud Link", learningPage, learningPageCount, setLearningPage, learningScrollerRef)}
      </section>
    </div>
  );
}

