  useEffect(() => {
    void linkApi.getAgentControlPlaneAuthStatus().then(setAcpAuth);
  }, []);

  useEffect(() => {
    let cancelled = false;

    async function loadReadiness() {
      const [nextWhisper, nextWebRtc, nextSpeakSettings, nextHarperStatus, nextStorageBackupStatus, nextSessionDaemonReadiness] = await Promise.allSettled([
        linkApi.getWhisperStatus(),
        linkApi.getWebRtcStatus(),
        linkApi.getSpeakSettings(),
        getHarperAddonStatus({ forceRefresh: false, allowAutoUpdate: true }),
        linkApi.getStorageBackupStatus(),
        linkApi.getSessionDaemonReadiness(),
      ]);
      if (cancelled) return;
      if (nextWhisper.status === "fulfilled") setWhisperStatus(nextWhisper.value);
      if (nextWebRtc.status === "fulfilled") setWebRtcStatus(nextWebRtc.value);
      if (nextSpeakSettings.status === "fulfilled") setSpeakSettings(nextSpeakSettings.value);
      if (nextHarperStatus.status === "fulfilled") setHarperStatus(nextHarperStatus.value);
      if (nextStorageBackupStatus.status === "fulfilled") setStorageBackupStatus(nextStorageBackupStatus.value);
      if (nextSessionDaemonReadiness.status === "fulfilled") setSessionDaemonReadiness(nextSessionDaemonReadiness.value);
    }

    void loadReadiness();
    return () => {
      cancelled = true;
    };
  }, []);

  useEffect(() => {
    window.localStorage.setItem(internalTestingChecklistStorageKey, JSON.stringify(testingChecklist));
  }, [testingChecklist]);

  async function signInOkta() {
    setBusy("okta");
    setAcpAuth(await linkApi.signInAgentControlPlane());
    await refresh();
    setBusy("");
  }

  async function markStep(stepId: string) {
    const nextIds = [...new Set([...onboarding.completedStepIds, stepId])];
    const next = await linkApi.updateOnboarding({ completedStepIds: nextIds });
    setOnboarding(next);
  }

  async function toggleConfigurationStep(stepId: string, checked: boolean) {
    const nextIds = checked
      ? [...new Set([...onboarding.completedStepIds, stepId])]
      : onboarding.completedStepIds.filter((id) => id !== stepId);
    const next = await linkApi.updateOnboarding({ completedStepIds: nextIds });
    setOnboarding(next);
  }

  async function dismissOnboarding() {
    const next = await linkApi.updateOnboarding({ dismissed: true });
    setOnboarding(next);
    setView("chats");
  }

  function selectIntroSlide(index: number) {
    const nextIndex = (index + introSlides.length) % introSlides.length;
    setIntroSlideIndex(nextIndex);
  }

  function stepIntroSlide(direction: -1 | 1) {
    selectIntroSlide(introSlideIndex + direction);
  }

  function toggleTestingChecklistItem(itemId: string) {
    setTestingChecklist((current) =>
      current.includes(itemId) ? current.filter((id) => id !== itemId) : [...current, itemId],
    );
  }

  async function startFeedbackReport() {
    await startPromptChat([
      "Internal testing feedback report.",
      "Help me turn this into a concise Cloud Link bug report or product feedback note. Ask for the missing reproduction details, expected behavior, actual behavior, and severity.",
      "",
      "Current readiness context:",
      testerContext,
    ].join("\n"), "Internal testing feedback");
    if (!testingChecklist.includes("feedback")) setTestingChecklist((current) => [...current, "feedback"]);
  }

  function renderOnboardingArrowActions(actions: ReactNode) {
    const nodes = extractOnboardingActionNodes(actions);
    if (nodes.length === 0) return null;
    return (
      <div className="onboardingArrowActions">
        {nodes.map((node, index) => (
          <div className="onboardingArrowAction" key={index}>
            <span className="onboardingArrowActionLabel">{node}</span>
            <ArrowRight size={16} />
          </div>
        ))}
      </div>
    );
  }

  function extractOnboardingActionNodes(actions: ReactNode) {
    if (!actions) return [];
    return Children.toArray(actions).flatMap((node) => {
      if (isValidElement<{ children?: ReactNode }>(node) && node.props.children) {
        return Children.toArray(node.props.children).filter(Boolean);
      }
      return [node];
    });
  }

  function renderOnboardingStepButtons(actions: ReactNode) {
    const nodes = extractOnboardingActionNodes(actions);
    if (nodes.length === 0) return null;
    return (
      <div className="onboardingStepButtons">
        {nodes.map((node, index) => (
          <span className="onboardingStepButtonSlot" key={index}>{node}</span>
        ))}
      </div>
    );
  }

